$ErrorActionPreference = 'Stop'
$token = [Environment]::GetEnvironmentVariable('DCOIR_AIRTABLE_TOKEN','Machine')
$baseId = [Environment]::GetEnvironmentVariable('DCOIR_AIRTABLE_BASE_ID','Machine')
if ([string]::IsNullOrWhiteSpace($token)) { throw 'DCOIR_AIRTABLE_TOKEN is not available in Machine scope.' }
if ([string]::IsNullOrWhiteSpace($baseId)) { throw 'DCOIR_AIRTABLE_BASE_ID is not available in Machine scope.' }
$out = [Environment]::GetEnvironmentVariable('DCOIR_DOWNLOADS_DIR','Machine')
$headers = @{ Authorization = "Bearer $token" }
$uri = "https://api.airtable.com/v0/meta/bases/$baseId/tables"
$schema = Invoke-RestMethod -Uri $uri -Headers $headers -Method GET
# Write sanitized view metadata analysis only. Do not print/export token values.
